import 'package:flutter_test/flutter_test.dart';\nimport 'package:chefmind_ai_app/features/recipes/domain/entities/instruction.dart';\n\nvoid main() {\n  group('Instruction Entity Tests', () {\n    late Instruction testInstruction;\n    late TimerInfo testTimer;\n\n    setUp(() {\n      testTimer = const TimerInfo(\n        duration: Duration(minutes: 10),\n        name: 'Sauté Timer',\n        description: 'Sauté until golden brown',\n        type: TimerType.countdown,\n        isAutoStart: true,\n        isRequired: true,\n        priority: TimerPriority.high,\n      );\n\n      testInstruction = Instruction(\n        id: 'inst-001',\n        stepNumber: 1,\n        description: 'Heat olive oil in a large skillet over medium-high heat. Add onions and sauté until golden brown and caramelized.',\n        title: 'Prepare the Base',\n        ingredients: ['olive oil', 'onions'],\n        equipment: ['large skillet'],\n        duration: const Duration(minutes: 10),\n        passiveTime: const Duration(minutes: 2),\n        techniques: ['sauteing', 'caramelizing'],\n        temperature: '350°F (175°C)',\n        imageUrl: 'https://example.com/step1.jpg',\n        tips: ['Don\\'t rush the caramelization process', 'Stir occasionally to prevent burning'],\n        warnings: ['Watch carefully to avoid burning'],\n        type: InstructionType.cooking,\n        difficulty: DifficultyLevel.medium,\n        isOptional: false,\n        isCritical: true,\n        nextStepCondition: 'Onions are golden brown and soft',\n        visualCues: ['Golden brown color', 'Soft texture'],\n        sensoryIndicators: ['Sweet aroma', 'Sizzling sound'],\n        timer: testTimer,\n        commonMistakes: ['Using too high heat', 'Not stirring enough'],\n        troubleshooting: 'If onions start to burn, reduce heat and add a splash of water',\n      );\n    });\n\n    test('should create instruction with all properties', () {\n      expect(testInstruction.id, 'inst-001');\n      expect(testInstruction.stepNumber, 1);\n      expect(testInstruction.description, contains('Heat olive oil'));\n      expect(testInstruction.title, 'Prepare the Base');\n      expect(testInstruction.ingredients.length, 2);\n      expect(testInstruction.equipment.length, 1);\n      expect(testInstruction.techniques.length, 2);\n      expect(testInstruction.tips.length, 2);\n      expect(testInstruction.warnings.length, 1);\n    });\n\n    test('should have correct default values', () {\n      const minimalInstruction = Instruction(\n        id: 'inst-002',\n        stepNumber: 2,\n        description: 'Mix ingredients together',\n      );\n\n      expect(minimalInstruction.ingredients, isEmpty);\n      expect(minimalInstruction.equipment, isEmpty);\n      expect(minimalInstruction.techniques, isEmpty);\n      expect(minimalInstruction.tips, isEmpty);\n      expect(minimalInstruction.warnings, isEmpty);\n      expect(minimalInstruction.type, InstructionType.preparation);\n      expect(minimalInstruction.difficulty, DifficultyLevel.easy);\n      expect(minimalInstruction.isOptional, false);\n      expect(minimalInstruction.isCritical, false);\n    });\n\n    test('should serialize to and from JSON correctly', () {\n      final json = testInstruction.toJson();\n      final deserialized = Instruction.fromJson(json);\n\n      expect(deserialized.id, testInstruction.id);\n      expect(deserialized.stepNumber, testInstruction.stepNumber);\n      expect(deserialized.description, testInstruction.description);\n      expect(deserialized.title, testInstruction.title);\n      expect(deserialized.ingredients, testInstruction.ingredients);\n      expect(deserialized.equipment, testInstruction.equipment);\n      expect(deserialized.type, testInstruction.type);\n      expect(deserialized.difficulty, testInstruction.difficulty);\n    });\n\n    test('should handle copyWith correctly', () {\n      final updated = testInstruction.copyWith(\n        stepNumber: 2,\n        title: 'Updated Title',\n        difficulty: DifficultyLevel.hard,\n        isOptional: true,\n      );\n\n      expect(updated.stepNumber, 2);\n      expect(updated.title, 'Updated Title');\n      expect(updated.difficulty, DifficultyLevel.hard);\n      expect(updated.isOptional, true);\n      // Other fields should remain the same\n      expect(updated.id, testInstruction.id);\n      expect(updated.description, testInstruction.description);\n      expect(updated.type, testInstruction.type);\n    });\n\n    test('should handle duration and passive time correctly', () {\n      expect(testInstruction.duration?.inMinutes, 10);\n      expect(testInstruction.passiveTime?.inMinutes, 2);\n    });\n\n    test('should handle timer information correctly', () {\n      expect(testInstruction.timer?.duration.inMinutes, 10);\n      expect(testInstruction.timer?.name, 'Sauté Timer');\n      expect(testInstruction.timer?.type, TimerType.countdown);\n      expect(testInstruction.timer?.isAutoStart, true);\n      expect(testInstruction.timer?.isRequired, true);\n      expect(testInstruction.timer?.priority, TimerPriority.high);\n    });\n\n    test('should handle visual and sensory cues', () {\n      expect(testInstruction.visualCues.length, 2);\n      expect(testInstruction.visualCues, contains('Golden brown color'));\n      expect(testInstruction.sensoryIndicators.length, 2);\n      expect(testInstruction.sensoryIndicators, contains('Sweet aroma'));\n    });\n\n    test('should handle tips and warnings', () {\n      expect(testInstruction.tips.length, 2);\n      expect(testInstruction.tips.first, contains('caramelization'));\n      expect(testInstruction.warnings.length, 1);\n      expect(testInstruction.warnings.first, contains('burning'));\n    });\n\n    test('should handle troubleshooting information', () {\n      expect(testInstruction.troubleshooting, contains('reduce heat'));\n      expect(testInstruction.commonMistakes.length, 2);\n      expect(testInstruction.commonMistakes, contains('Using too high heat'));\n    });\n  });\n\n  group('TimerInfo Tests', () {\n    test('should create timer with required fields', () {\n      const timer = TimerInfo(\n        duration: Duration(minutes: 5),\n        name: 'Boil Timer',\n      );\n\n      expect(timer.duration.inMinutes, 5);\n      expect(timer.name, 'Boil Timer');\n      expect(timer.type, TimerType.countdown);\n      expect(timer.isAutoStart, false);\n      expect(timer.isRequired, false);\n      expect(timer.priority, TimerPriority.normal);\n    });\n\n    test('should serialize timer correctly', () {\n      const timer = TimerInfo(\n        duration: Duration(hours: 1, minutes: 30),\n        name: 'Slow Cook Timer',\n        description: 'Cook on low heat',\n        type: TimerType.countdown,\n        isAutoStart: true,\n        isRequired: true,\n        soundAlert: 'gentle_chime',\n        priority: TimerPriority.critical,\n      );\n\n      final json = timer.toJson();\n      final deserialized = TimerInfo.fromJson(json);\n\n      expect(deserialized.duration.inMinutes, 90);\n      expect(deserialized.name, 'Slow Cook Timer');\n      expect(deserialized.type, TimerType.countdown);\n      expect(deserialized.priority, TimerPriority.critical);\n    });\n  });\n\n  group('Instruction Enums Tests', () {\n    test('InstructionType enum should have all types', () {\n      expect(InstructionType.values.length, greaterThan(10));\n      expect(InstructionType.values, contains(InstructionType.preparation));\n      expect(InstructionType.values, contains(InstructionType.cooking));\n      expect(InstructionType.values, contains(InstructionType.baking));\n      expect(InstructionType.values, contains(InstructionType.mixing));\n      expect(InstructionType.values, contains(InstructionType.assembly));\n      expect(InstructionType.values, contains(InstructionType.plating));\n    });\n\n    test('DifficultyLevel enum should have all levels', () {\n      expect(DifficultyLevel.values.length, 5);\n      expect(DifficultyLevel.values, contains(DifficultyLevel.beginner));\n      expect(DifficultyLevel.values, contains(DifficultyLevel.easy));\n      expect(DifficultyLevel.values, contains(DifficultyLevel.medium));\n      expect(DifficultyLevel.values, contains(DifficultyLevel.hard));\n      expect(DifficultyLevel.values, contains(DifficultyLevel.expert));\n    });\n\n    test('TimerType enum should have all types', () {\n      expect(TimerType.values.length, 4);\n      expect(TimerType.values, contains(TimerType.countdown));\n      expect(TimerType.values, contains(TimerType.stopwatch));\n      expect(TimerType.values, contains(TimerType.interval));\n      expect(TimerType.values, contains(TimerType.reminder));\n    });\n\n    test('TimerPriority enum should have all priorities', () {\n      expect(TimerPriority.values.length, 4);\n      expect(TimerPriority.values, contains(TimerPriority.low));\n      expect(TimerPriority.values, contains(TimerPriority.normal));\n      expect(TimerPriority.values, contains(TimerPriority.high));\n      expect(TimerPriority.values, contains(TimerPriority.critical));\n    });\n\n    test('CookingTechnique enum should have comprehensive techniques', () {\n      expect(CookingTechnique.values.length, greaterThan(25));\n      expect(CookingTechnique.values, contains(CookingTechnique.sauteing));\n      expect(CookingTechnique.values, contains(CookingTechnique.frying));\n      expect(CookingTechnique.values, contains(CookingTechnique.boiling));\n      expect(CookingTechnique.values, contains(CookingTechnique.roasting));\n      expect(CookingTechnique.values, contains(CookingTechnique.grilling));\n      expect(CookingTechnique.values, contains(CookingTechnique.sousVide));\n    });\n  });\n\n  group('Instruction Edge Cases', () {\n    test('should handle instructions with no duration', () {\n      const instruction = Instruction(\n        id: 'inst-003',\n        stepNumber: 3,\n        description: 'Serve immediately',\n        type: InstructionType.plating,\n      );\n\n      expect(instruction.duration, isNull);\n      expect(instruction.passiveTime, isNull);\n      expect(instruction.timer, isNull);\n    });\n\n    test('should handle optional instructions', () {\n      const instruction = Instruction(\n        id: 'inst-004',\n        stepNumber: 4,\n        description: 'Garnish with fresh herbs if desired',\n        type: InstructionType.garnishing,\n        isOptional: true,\n        difficulty: DifficultyLevel.easy,\n      );\n\n      expect(instruction.isOptional, true);\n      expect(instruction.type, InstructionType.garnishing);\n    });\n\n    test('should handle critical instructions with warnings', () {\n      const instruction = Instruction(\n        id: 'inst-005',\n        stepNumber: 5,\n        description: 'Heat oil to exactly 350°F for deep frying',\n        type: InstructionType.cooking,\n        isCritical: true,\n        warnings: [\n          'Oil temperature is critical for safety and quality',\n          'Never leave hot oil unattended',\n          'Have fire extinguisher nearby'\n        ],\n        temperature: '350°F (175°C)',\n        equipment: ['deep fryer', 'thermometer'],\n      );\n\n      expect(instruction.isCritical, true);\n      expect(instruction.warnings.length, 3);\n      expect(instruction.warnings, contains('fire extinguisher'));\n    });\n\n    test('should handle complex multi-step instructions', () {\n      const instruction = Instruction(\n        id: 'inst-006',\n        stepNumber: 6,\n        description: 'Make the roux by whisking flour into the hot butter mixture. Cook, stirring constantly, until the mixture turns golden brown and smells nutty.',\n        title: 'Prepare Brown Roux',\n        type: InstructionType.cooking,\n        difficulty: DifficultyLevel.hard,\n        duration: Duration(minutes: 15),\n        techniques: ['whisking', 'stirring', 'browning'],\n        temperature: 'medium heat',\n        visualCues: ['Golden brown color', 'Smooth consistency'],\n        sensoryIndicators: ['Nutty aroma', 'No raw flour smell'],\n        tips: [\n          'Whisk constantly to prevent lumps',\n          'Don\\'t rush - proper browning takes time'\n        ],\n        warnings: ['Roux can burn quickly once it starts browning'],\n        commonMistakes: [\n          'Stopping too early',\n          'Using too high heat',\n          'Not whisking enough'\n        ],\n      );\n\n      expect(instruction.difficulty, DifficultyLevel.hard);\n      expect(instruction.techniques.length, 3);\n      expect(instruction.visualCues.length, 2);\n      expect(instruction.tips.length, 2);\n      expect(instruction.commonMistakes.length, 3);\n    });\n\n    test('should handle instructions with multiple timers', () {\n      const primaryTimer = TimerInfo(\n        duration: Duration(minutes: 20),\n        name: 'Bake Timer',\n        type: TimerType.countdown,\n        isRequired: true,\n        priority: TimerPriority.high,\n      );\n\n      const instruction = Instruction(\n        id: 'inst-007',\n        stepNumber: 7,\n        description: 'Bake in preheated oven for 20 minutes, then check for doneness',\n        type: InstructionType.baking,\n        timer: primaryTimer,\n        nextStepCondition: 'Toothpick comes out clean',\n        troubleshooting: 'If not done, bake for 5 more minutes and check again',\n      );\n\n      expect(instruction.timer?.name, 'Bake Timer');\n      expect(instruction.timer?.isRequired, true);\n      expect(instruction.nextStepCondition, contains('toothpick'));\n    });\n\n    test('should handle passive time instructions', () {\n      const instruction = Instruction(\n        id: 'inst-008',\n        stepNumber: 8,\n        description: 'Let dough rise in a warm place until doubled in size',\n        type: InstructionType.resting,\n        duration: Duration(minutes: 5), // Active time to set up\n        passiveTime: Duration(hours: 2), // Passive rising time\n        nextStepCondition: 'Dough has doubled in size',\n        visualCues: ['Dough is puffy', 'Finger poke test leaves indent'],\n        tips: ['Cover with damp towel to prevent drying'],\n      );\n\n      expect(instruction.duration?.inMinutes, 5);\n      expect(instruction.passiveTime?.inHours, 2);\n      expect(instruction.type, InstructionType.resting);\n    });\n  });\n}\n